// Fail-closed: only the platform bridge (shared secret) may drive this workflow.
const got = $input.first().json.headers?.['x-gaiada-bridge-secret'];
if (!got || got !== $env.N8N_BRIDGE_SECRET) throw new Error('bad bridge secret');
const e = $input.first().json.body ?? {};
if (e.v !== 1) throw new Error(`unexpected envelope version ${e.v}`);
return [{ json: { text: `\ud83c\udff7\ufe0f Org structure updated for tenant ${e.tenantId} (entity ${e.entityId}) at ${e.createdAt}`, event: e } }];
